      h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
    }
    function hex(n){return('00000000'+(n>>>0).toString(16)).slice(-8);}
    const hexStr = hex(h0)+hex(h1)+hex(h2)+hex(h3)+hex(h4)+hex(h5)+hex(h6)+hex(h7);
    // return as byte array
    const result = [];
    for (let i = 0; i < hexStr.length; i += 2) result.push(parseInt(hexStr.substr(i, 2), 16));
    return result;
  }
  const BLOCK_SIZE = 64;
  let keyBytes = strToBytes(keyStr);
  if (keyBytes.length > BLOCK_SIZE) keyBytes = sha256Raw(keyBytes);
  while (keyBytes.length < BLOCK_SIZE) keyBytes.push(0);
  const ipad = keyBytes.map(b => b ^ 0x36);
  const opad = keyBytes.map(b => b ^ 0x5C);
  const msgBytes = strToBytes(msgStr);
  const innerHash = sha256Raw([...ipad, ...msgBytes]);
  const outerHash = sha256Raw([...opad, ...innerHash]);
  return outerHash.map(b => ('00' + b.toString(16)).slice(-2)).join('');
}

const slackSigSecret = $env.SLACK_SIGNING_SECRET;
if (!slackSigSecret) throw new Error('SLACK_SIGNING_SECRET not in env');

const headers = $('Webhook Slack Interactive').item.json.headers || {};
const ts = headers['x-slack-request-timestamp'];
const tsNum = parseInt(ts, 10);
if (!ts || isNaN(tsNum) || tsNum <= 0 || Math.abs((Date.now() / 1000) - tsNum) > 300) {
  throw new Error('Slack request timestamp out of range (possible replay attack)');
}

// Read the raw bytes Slack signed. options.rawBody=true on the Webhook node
// preserves the original request body under item.binary.data (base64).
// See n8n-nodes-base/dist/nodes/Webhook/Webhook.node.js lines 220-238 for the binary attachment.
const upstreamItem = $('Webhook Slack Interactive').first();
const binaryWrapper = upstreamItem.binary && upstreamItem.binary.data;
if (!binaryWrapper || !binaryWrapper.data) {
  // Defensive: if rawBody isn't enabled on the webhook node, surface a clear diagnostic.
  throw new Error('Raw body not available \u2014 set options.rawBody=true on Webhook Slack Interactive');
}
const rawBody = Buffer.from(binaryWrapper.data, 'base64').toString('utf8');
const bodyPayload = $('Webhook Slack Interactive').item.json.body && $('Webhook Slack Interactive').item.json.body.payload;
if (!bodyPayload) throw new Error('No payload field in Slack request body');

const sigBase = `v0:${ts}:${rawBody}`;
const expected = 'v0=' + hmacSha256(slackSigSecret, sigBase);
const got = headers['x-slack-signature'];
if (!got) throw new Error('Missing X-Slack-Signature header');
function safeEqual(a, b) {
  if (a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}
if (!safeEqual(got, expected)) throw new Error('Invalid Slack signature');

const payload = JSON.parse(bodyPayload);
if (!payload.actions || !payload.actions[0]) throw new Error('No actions in Slack payload');
const action = payload.actions[0];
const actionId = action.action_id || '';

const slack_user_id = payload.user && payload.user.id;
const slack_user_name = (payload.user && (payload.user.username || payload.user.name)) || 'unknown';
const response_url = payload.response_url || null;

// action_id formats:
//   - 'reject_<oid>'                                 (reject button)
//   - 'approve_<platform_key>_<oid>'                 (per-platform approve button; platform_key from PLATFORM_MAP)
//   - 'open_form_<oid>'                              (Slack link-button telemetry, ignored)
//   - anything else                                  (unknown — ignored, e.g. Slack auto-IDs like 'e/DS5')
// Unknown / non-actionable verbs short-circuit to a 200 via the downstream IF
// gate; only 'approve' and 'reject' continue into the DB write path.
const firstUnder = actionId.indexOf('_');
const lastUnder = actionId.lastIndexOf('_');

function ignored() {
  return [{json: {
    verb: 'ignore',
    platform_key: null,
    outreach_item_id: null,
    slack_user_id,
    slack_user_name,
    response_url,
  }}];
}

if (firstUnder < 0) {
  // No underscore at all (e.g. Slack auto-assigned 'e/DS5') — ignore.
  return ignored();
}

const rawVerb = actionId.substring(0, firstUnder);
// Recognise the open_form_<oid> prefix as a single composite verb.
const verb = (actionId.startsWith('open_form_')) ? 'open_form' : rawVerb;

if (!['approve', 'reject'].includes(verb)) {
  // Includes 'open_form' and anything else not in the actionable set.
  return ignored();
}

const outreachItemIdStr = actionId.substring(lastUnder + 1);
const outreach_item_id = parseInt(outreachItemIdStr, 10);
if (isNaN(outreach_item_id) || outreach_item_id <= 0) throw new Error('Invalid outreach_item_id: ' + outreachItemIdStr);

// platform_key is the slice between the first and last underscores (only present on approve).
let platform_key = null;
if (verb === 'approve') {
  if (lastUnder === firstUnder) {
    throw new Error('Approve action_id missing platform_key: ' + actionId);
  }
  platform_key = actionId.substring(firstUnder + 1, lastUnder);
  if (!platform_key) throw new Error('Empty platform_key in action_id: ' + actionId);
} else if (verb === 'reject') {
  // Reject must be bi-segment (reject_<oid>) — extra segments are a bug.
  if (lastUnder !== firstUnder) {
    throw new Error('Reject action_id has unexpected platform_key segment: ' + actionId);
  }
}

return [{json: {
  verb,
  platform_key,
  outreach_item_id,
  slack_user_id,
  slack_user_name,
  response_url,
}}];

const draft = $input.item.json;
const sig = $('Verify Slack Signature').item.json;

if (!draft || draft.draft_id === null || draft.draft_id === undefined) {
  return [{json: {
    _route: 'no_draft',
    verb: sig.verb,
    response_url: sig.response_url,
    slack_user_name: sig.slack_user_name,
    error_msg: 'No pending helpful_only draft found for item #' + sig.outreach_item_id,
  }}];
}

const verb = sig.verb;
const risk = Number(draft.risk_score);
let route;
if (verb === 'reject') {
  route = 'write';
} else if (verb === 'approve' && risk < 20) {
  route = 'write';
} else if (verb === 'approve' && risk >= 20) {
  route = 'risk_too_high';
} else {
  route = 'no_draft';
}

return [{json: {
  _route: route,
  verb,
  draft_id: draft.draft_id,
  risk_score: risk,
  draft_text: draft.draft_text,
  suggested_destination: draft.suggested_destination || '',
  suggested_post_type: draft.suggested_post_type || '',
  outreach_item_id: sig.outreach_item_id,
  slack_user_id: sig.slack_user_id,
  slack_user_name: sig.slack_user_name,
  response_url: sig.response_url,
}}];

function sha256(str) {
